const d = $json.payload || $json;

function semEmoji(s) { return ({ verde: '🟢', amarillo: '🟡', rojo: '🔴', gris: '⚪' })[s] || '⚪'; }

function renderFase(f) {
  const lines = [semEmoji(f.semaforo) + ' ' + f.nombre + ' (' + f.completadas + '/' + f.total + ' = ' + f.pct + '%)'];
  for (const t of f.tareas) {
    const status = t.completada ? '[✓]' : (t.vencida ? '[✗ VENCIDA]' : '[⏳]');
    const resp = t.responsables.length > 0 ? t.responsables.join(', ') : 'SIN ASIGNAR';
    const due = t.fecha_limite ? ' due=' + t.fecha_limite.slice(0, 10) : ' (sin fecha)';
    const chk = t.checklist_total > 0 ? ' checklist=' + t.checklist_done + '/' + t.checklist_total : '';
    const adj = t.adjuntos_count > 0 ? ' adj=' + t.adjuntos_count : '';
    lines.push('  ' + status + ' ' + t.nombre + ' -> ' + resp + due + chk + adj);
  }
  return lines.join('\n');
}

const fasesStr = Object.values(d.fases).map(renderFase).join('\n\n');

const commitsBackStr = d.github.top_commits_back.map(c => '  ' + c.sha + ' ' + c.autor + ': ' + c.mensaje + ' (' + (c.fecha || '').slice(0, 10) + ')').join('\n') || '  (sin commits)';
const commitsFrontStr = d.github.top_commits_front.map(c => '  ' + c.sha + ' ' + c.autor + ': ' + c.mensaje + ' (' + (c.fecha || '').slice(0, 10) + ')').join('\n') || '  (sin commits)';

const entregables = d.snapshot_tareas
  .filter(t => (t.archivos.length > 0 || t.enlaces.length > 0) && t.nombre && t.nombre.trim() !== '.')
  .sort((a, b) => new Date(b.dateLastActivity || 0) - new Date(a.dateLastActivity || 0))
  .slice(0, 15)
  .map(t => {
    const files = t.archivos.map(a => a.name).join(', ');
    const links = t.enlaces.map(l => (l.name || l.url)).join(', ');
    const parts = [files, links].filter(Boolean).join(' | ');
    return '  [' + t.lista + '] ' + t.nombre + ': ' + parts;
  }).join('\n') || '  (ninguno)';

const rankingStr = d.ranking.map(r => '  ' + r.initials + ' ' + r.trello_name + ': ' + r.tareas_done + '✓ / ' + r.tareas_pending + '⏳ / ' + r.tareas_overdue + '✗   commits14d=' + r.commits_14d).join('\n') || '  (sin datos)';

const ciBack = d.github.ci_back ? d.github.ci_back.status + ' en ' + d.github.ci_back.branch + ' (' + (d.github.ci_back.date || '').slice(0, 10) + ')' : 'sin datos';
const ciFront = d.github.ci_front ? d.github.ci_front.status + ' en ' + d.github.ci_front.branch + ' (' + (d.github.ci_front.date || '').slice(0, 10) + ')' : 'sin datos';

function sign(n) { return n >= 0 ? '+' + n : String(n); }
const diffStr = d.diff_previa ? 'progreso ' + sign(d.diff_previa.progreso) + '% | vencidas ' + sign(d.diff_previa.vencidas) + ' | commits14d ' + sign(d.diff_previa.commits_14d) : 'sin previa';

const staleStr = d.cards_stale.slice(0, 5).map(t => t.nombre + '(' + t.dias_sin_actividad + 'd, ' + (t.responsables[0] || 'sin asignar') + ')').join(', ') || 'ninguna';
const sinAsignarStr = d.cards_sin_asignar.slice(0, 5).map(t => t.nombre).join(', ') || 'ninguna';
const sinFechaStr = d.cards_sin_fecha.slice(0, 5).map(t => t.nombre).join(', ') || 'ninguna';

const prompt = 'Eres gestor PM del proyecto PetSafe (clínica veterinaria, NestJS backend + Angular frontend, fin programado 2026-06-10). Analiza estado real y da diagnóstico accionable en español, texto plano, SIN markdown, SIN asteriscos, SIN emojis.\n\n' +
'Estructura OBLIGATORIA, cada sección máx 3 oraciones:\n' +
'RESUMEN: estado global (verde/amarillo/rojo) con motivo principal en una línea.\n' +
'POR FASE: comenta SOLO las fases con problemas o riesgo, menciona tareas específicas por nombre.\n' +
'CARGA EQUIPO: observación sobre distribución de trabajo entre FG, DM, DP, JA.\n' +
'RIESGOS: top 3 con severidad y causa (no inventes, usa los datos).\n' +
'ACCIONES: 3 acciones concretas asignadas por nombre real (ej: Josué revisar PR X, David Barragán desbloquear tarea Y).\n' +
'PROYECCION: llegamos al 10-jun-2026? sí/no/riesgo con justificación numérica.\n\n' +
'=== CONTEXTO REAL ===\n' +
'Fecha: ' + d.fecha + '\n' +
'Progreso global: ' + d.progreso_pct + '% (' + d.total_completadas + '/' + d.total_tarjetas + ')\n' +
'Días hasta fin proyecto: ' + d.kpis.dias_hasta_fin + '\n' +
'Proyección calculada: ' + d.kpis.proyeccion + '\n' +
'Velocidad: ' + d.kpis.velocidad_tareas_por_dia + ' tareas/día (' + d.kpis.completadas_7d + ' completadas últimos 7d)\n' +
'Diff vs análisis previo: ' + diffStr + '\n' +
'Tendencia histórica: ' + d.tendencia_historial + '\n\n' +
'=== TAREAS POR FASE (completo) ===\n' +
fasesStr + '\n\n' +
'=== CARDS PROBLEMÁTICAS ===\n' +
'Stale (sin actividad >5d): ' + d.cards_stale.length + ' -> ' + staleStr + '\n' +
'Sin asignar: ' + d.cards_sin_asignar.length + ' -> ' + sinAsignarStr + '\n' +
'Sin fecha: ' + d.cards_sin_fecha.length + ' -> ' + sinFechaStr + '\n\n' +
'=== GITHUB ===\n' +
'Commits 14d back=' + d.github.commits_back + ' front=' + d.github.commits_front + '\n' +
'Silencio back=' + d.kpis.silencio_back_dias + 'd front=' + d.kpis.silencio_front_dias + 'd\n' +
'% commits convencionales (feat/fix/etc): ' + d.kpis.pct_commits_convencionales + '%\n' +
'Bus factor 14d (autores distintos): ' + d.kpis.bus_factor_14d + '\n' +
'PRs abiertos: ' + (d.github.prs_abiertos_back + d.github.prs_abiertos_front) + ' (avg ' + d.kpis.pr_open_time_dias + 'd open)\n' +
'CI backend: ' + ciBack + '\n' +
'CI frontend: ' + ciFront + '\n' +
'Deploy front: ' + d.github.deploy_front_url + '\n\n' +
'Top 5 commits backend:\n' + commitsBackStr + '\n\n' +
'Top 5 commits frontend:\n' + commitsFrontStr + '\n\n' +
'=== CARGA POR PERSONA ===\n' +
rankingStr + '\n\n' +
'=== ENTREGABLES (archivos + enlaces) ===\n' +
entregables + '\n\n' +
'=== HITOS PRÓXIMOS ===\n' +
(d.hitos_proximos.map(h => h.nombre + ' (' + h.dias_faltan + 'd, resp=' + h.responsable + ')').join('\n') || '(ninguno)') + '\n\n' +
'Problemas auto-detectados: ' + JSON.stringify(d.problemas_detectados) + '\n' +
'Severidad máxima: ' + d.severidad_max;

return [{ json: { prompt, gemini_key: d.gemini_key, discord_url: d.discord_url, analysis: d } }];

const d = $node['Preparar Prompt'].json.analysis || $json.analysis || $json.payload || $json;
const geminiResp = $node['Gemini Análisis'].json;
const iaText =
  geminiResp?.text ||
  geminiResp?.response?.generations?.[0]?.[0]?.text?.trim() ||
  geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() ||
  '(sin respuesta IA)';

const colorMap = { alta: 15158332, media: 16761095, baja: 3066993 };
const color = colorMap[d.severidad_max] || 3066993;

function semEmoji(s) { return ({ verde: '🟢', amarillo: '🟡', rojo: '🔴', gris: '⚪' })[s] || '⚪'; }

const resumen1 = semEmoji(d.severidad_max === 'alta' ? 'rojo' : d.severidad_max === 'media' ? 'amarillo' : 'verde') + ' **' + d.progreso_pct + '%** progreso · ' + d.total_completadas + '/' + d.total_tarjetas + ' tareas · **' + d.kpis.dias_hasta_fin + 'd** hasta fin';
const resumen2 = '📈 Proyección: **' + d.kpis.proyeccion + '** · Velocidad ' + d.kpis.velocidad_tareas_por_dia + '/día · ' + d.kpis.completadas_7d + ' completadas últimos 7d';
function sign(n) { return n >= 0 ? '+' + n : String(n); }
const resumen3 = d.diff_previa ? '🔁 vs previa: ' + sign(d.diff_previa.progreso) + '% progreso, ' + sign(d.diff_previa.vencidas) + ' vencidas, ' + sign(d.diff_previa.commits_14d) + ' commits' : '🔁 primera ejecución';

const descripcion = [resumen1, resumen2, resumen3].join('\n');

const fields = [];

const fasesTxt = Object.values(d.fases).map(f => {
  const head = semEmoji(f.semaforo) + ' **' + f.nombre + '** ' + f.pct + '% (✓' + f.completadas + ' ⏳' + f.pendientes + ' ✗' + f.vencidas + ')';
  const tareasFiltered = f.tareas.filter(t => t.nombre && t.nombre.trim() !== '.');
  const details = tareasFiltered.slice(0, 8).map(t => {
    const ic = t.completada ? '✓' : (t.vencida ? '🔴' : '⏳');
    const r = t.responsables[0] ? ' · ' + t.responsables[0].split(' ').slice(0, 2).join(' ') : ' · sin asignar';
    return ic + ' ' + t.nombre.slice(0, 55) + r;
  }).join('\n');
  return head + '\n' + details;
});
const fasesFull = fasesTxt.join('\n\n');
fields.push({ name: '📋 Tareas por fase', value: fasesFull.slice(0, 1024), inline: false });

if (d.cards_stale.length > 0 || d.cards_sin_asignar.length > 0 || d.cards_sin_fecha.length > 0) {
  const lines = [];
  if (d.cards_stale.length > 0) lines.push('🕸️ **Stale**: ' + d.cards_stale.slice(0, 3).map(t => t.nombre + '(' + t.dias_sin_actividad + 'd)').join(', '));
  if (d.cards_sin_asignar.length > 0) lines.push('❓ **Sin asignar**: ' + d.cards_sin_asignar.slice(0, 3).map(t => t.nombre).join(', '));
  if (d.cards_sin_fecha.length > 0) lines.push('📅 **Sin fecha**: ' + d.cards_sin_fecha.slice(0, 3).map(t => t.nombre).join(', '));
  fields.push({ name: '⚠️ Cards problemáticas', value: lines.join('\n').slice(0, 1024), inline: false });
}

const commitBack = d.github.top_commits_back.slice(0, 5).map(c => '`' + c.sha + '` ' + c.autor.split(' ')[0] + ': ' + c.mensaje.slice(0, 60) + ' · ' + (c.fecha || '').slice(0, 10)).join('\n') || '(sin commits)';
const commitFront = d.github.top_commits_front.slice(0, 5).map(c => '`' + c.sha + '` ' + c.autor.split(' ')[0] + ': ' + c.mensaje.slice(0, 60) + ' · ' + (c.fecha || '').slice(0, 10)).join('\n') || '(sin commits)';
fields.push({ name: '📝 Commits backend (top 5)', value: commitBack.slice(0, 1024), inline: false });
fields.push({ name: '📝 Commits frontend (top 5)', value: commitFront.slice(0, 1024), inline: false });

const entregables = d.snapshot_tareas
  .filter(t => (t.archivos.length > 0 || t.enlaces.length > 0) && t.nombre && t.nombre.trim() !== '.')
  .sort((a, b) => new Date(b.dateLastActivity || 0) - new Date(a.dateLastActivity || 0))
  .slice(0, 6);
if (entregables.length > 0) {
  const entTxt = entregables.map(t => {
    const files = t.archivos.slice(0, 2).map(a => '[📄 ' + a.name + '](' + a.url + ')').join(' ');
    const links = t.enlaces.slice(0, 2).map(l => '[🔗 ' + (l.name || 'link') + '](' + l.url + ')').join(' ');
    return '**' + t.nombre.slice(0, 40) + '**: ' + [files, links].filter(Boolean).join(' ');
  }).join('\n');
  fields.push({ name: '📎 Entregables recientes', value: entTxt.slice(0, 1024), inline: false });
}



const kpiTxt = '⚡ Velocidad: ' + d.kpis.velocidad_tareas_por_dia + '/día · Bus factor: ' + d.kpis.bus_factor_14d + ' · Conv: ' + d.kpis.pct_commits_convencionales + '%\n' +
  '🔇 Silencio back: ' + d.kpis.silencio_back_dias + 'd · front: ' + d.kpis.silencio_front_dias + 'd\n' +
  '🔀 PRs abiertos: ' + (d.github.prs_abiertos_back + d.github.prs_abiertos_front) + ' · avg open ' + d.kpis.pr_open_time_dias + 'd · merge ratio ' + d.kpis.pr_merge_ratio_30d + '%';
fields.push({ name: '📊 KPIs', value: kpiTxt.slice(0, 1024), inline: false });

const ciStatusEmoji = s => s === 'success' ? '✅' : s === 'failure' ? '❌' : s === 'in_progress' ? '🟡' : '⚪';
const ciBackTxt = d.github.ci_back ? ciStatusEmoji(d.github.ci_back.status) + ' ' + d.github.ci_back.status + ' · `' + d.github.ci_back.branch + '` · [run](' + d.github.ci_back.url + ')' : '(sin datos)';
const ciFrontTxt = d.github.ci_front ? ciStatusEmoji(d.github.ci_front.status) + ' ' + d.github.ci_front.status + ' · `' + d.github.ci_front.branch + '` · [run](' + d.github.ci_front.url + ')' : '(sin datos)';
fields.push({ name: '🔧 CI', value: 'Backend: ' + ciBackTxt + '\nFrontend: ' + ciFrontTxt + '\n🌐 Deploy front: ' + d.github.deploy_front_url, inline: false });

if (d.hitos_proximos.length > 0) {
  const hitTxt = d.hitos_proximos.slice(0, 4).map(h => '📅 **' + h.nombre + '** en ' + h.dias_faltan + 'd (' + h.responsable + ')').join('\n');
  fields.push({ name: '🎯 Hitos próximos', value: hitTxt.slice(0, 1024), inline: false });
}

const iaResumen = iaText.length > 1000 ? iaText.slice(0, 1000) + '…' : iaText;
fields.push({ name: '🤖 Diagnóstico IA (Gemini)', value: iaResumen, inline: false });

const payload = {
  username: 'Monitor PetSafe',
  embeds: [{
    title: '📊 Estado proyecto PetSafe — ' + new Date().toLocaleDateString('es-ES'),
    description: descripcion.slice(0, 4000),
    color,
    fields,
    footer: { text: 'Monitor automático · ' + d.severidad_max.toUpperCase() + ' · ' + d.cantidad_problemas + ' problemas' },
    timestamp: d.fecha
  }]
};

return [{ json: { discord_payload: payload, ia_text: iaText, discord_url: $node['Preparar Prompt'].json.discord_url } }];

parameters.query:
UPDATE analisis_proyecto
SET recomendaciones_ia = '{{ ($json.ia_text || "").replace(/'/g, "''") }}'
WHERE id = (SELECT MAX(id) FROM analisis_proyecto);
